INSERT INTO `t_book` VALUES (1, 'NO1521203244709', '天蚕土豆', 'http://www.biquge5200.com/0_844/', '玄幻小说', '斗破苍穹', '这里是属于斗气的世界，没有花俏艳丽的魔法，有的，仅仅是繁衍到巅峰的斗气！想要知道异界的斗气在发展到巅峰之后是何种境地吗？请观斗破苍穹^^据调查，斗气，并非是国外产品，而是正宗的国产货，虽然斗气基本上已经泛滥在异界小说之中，不过土豆相信，斗破苍穹，能写出一些属于斗气的特色。', 'http://r.i.biquge5200.com/files/article/image/0/844/844s.jpg', b'0', '2018-03-16 20:27:29', '2018-03-16 20:36:50');
